initial_model.plantuml:
@startuml
class Customer {
    - customerId : String
}
class Order {
    - orderId : String
}
class Product {
    - name : String
    - description : String
}
class OrderItem {
    - quantityRequested : Integer
    - agreedPrice : Decimal
}
class Review {
    - dateWritten : Date
    - ratingScore : Integer
}
class PromotionalCampaign {
}
class ProductPromotion {
    - discountRate : Decimal
    - startDate : Date
    - endDate : Date
}
Customer "1" -- "0..*"  Order : Places
Order "1" *-- "1..*"  OrderItem
(Customer, Product) .. Review
(Product, PromotionalCampaign) .. ProductPromotion
@enduml

